from pycute.layout import Layout as LayoutRef, composition as compRef, coalesce as coalRef
from pycute import Layout, composition, coalesce, size, product, flatten

def random_layout(rank=2, max_shape=8, allow_neg=False, allow_zero_stride=False):
    """Generate a random Layout"""
    shape = tuple(random.randint(1, max_shape) for _ in range(rank))
    if random.random() < 0.5:
        # coalesced layout
        A = coalesce(Layout(tuple(shape), tuple(random.randint(0, max_shape) for _ in range(rank))))
    else:
        A = Layout(tuple(shape))
    return A

def brute_force_composition(A, B, max_iter=100):
    """Compute R(i) = A(B(i)) for all i in domain, verify linearity"""
    if isinstance(B, int):
        B = Layout(B)
    if B is None:
        return A

    # Compute B's domain
    if isinstance(B.shape, tuple):
        # Hierarchical
        s = 1
        for m in B.shape:
            s *= m
        domain = s
    else:
        domain = B.shape

    if domain > max_iter:
        return None  # Skip large domains

    # Compute R(i) for all i
    R_values = [A(B(i)) for i in range(domain)]

    # Check linearity
    if domain <= 1:
        # Rank-1, stride 0
        return Layout(B.shape, 0)

    R0 = R_values[0]
    R1 = R_values[1]
    stride = R1 - R0

    # Check all R(i) = R0 + i * stride
    for i in range(domain):
        if R_values[i] != R0 + i * stride:
            return None  # Not linear, can't represent as rank-1

    return Layout(B.shape, stride)

def check(a, b, brute=False):
    r_local = composition(a, b)
    r_ref = compRef(a, b)

