        print(f"  local: {r_local}")
        print(f"  ref:   {r_ref}")
        return False

    if brute:
        # Verify with brute force
        bf = brute_force_composition(a, b)
        if bf is not None and r_local != bf:
            # Only compare if both are rank-1
            if not isinstance(r_local.shape, tuple) and not isinstance(bf.shape, tuple):
                print(f"BRUTE MISMATCH: composition({a}, {b})")
                print(f"  algo: {r_local}")
                print(f"  brute: {bf}")
                return False

    return True

