from pycute import Layout, composition, coalesce, size, product, flatten

def brute_force_composition(A, B, max_iter=200):
    """Compute R(i) = A(B(i)) for all i in domain, return result"""
    if isinstance(B, int):
        B = Layout(B)
    if B is None:
        return A

    # Compute B's domain
    if isinstance(B.shape, tuple):
        s = 1
        for m in B.shape:
            s *= m
        domain = s
    else:
        domain = B.shape

    if domain > max_iter:
        return None  # Skip large domains

    # Compute R(i) for all i
    R_values = [A(B(i)) for i in range(domain)]

    # Check linearity
    if domain == 0:
        return Layout(0, 0)
    if domain == 1:
        return Layout(1, R_values[0])

    R0 = R_values[0]
    R1 = R_values[1]
    stride = R1 - R0

    # Check all R(i) = R0 + i * stride
    for i in range(domain):
        if R_values[i] != R0 + i * stride:
            # Not linear - return a hierarchical layout that captures it
            # For verification, we need to return something equivalent
            # Since we're using rank-1 layouts only for verification, return None
            return None

    return Layout(B.shape, stride)

def is_valid_composition_case(A, B):
    """Check if composition(A, B) is a valid case for the CUTLASS algorithm"""
    if B is None:
        return True
    if isinstance(B, int):
        return True
    if isinstance(B, tuple):
        return len(A) >= len(B)
    if isinstance(B.shape, tuple):
        return True
    # Rank-1 B
    # Check assert: curr_shape % rest_stride == 0 or rest_stride % curr_shape == 0
    flat_A = coalesce(A)
    rest_stride = B.stride
    if rest_stride == 0:
        return True
    for curr_shape in flatten(flat_A.shape)[:-1]:
        if not (curr_shape % rest_stride == 0 or rest_stride % curr_shape == 0):
            return False
    return True

# Run random tests
print("Running 500 random tests...")
fail_count = 0
total_count = 0
for trial in range(500):
    rank = random.randint(1, 3)
    a = Layout(tuple(random.randint(1, 6) for _ in range(rank)))

    # Generate B
    btype = random.choice(['int', 'rank1', 'tuple', 'hierarchical', 'none', 'zero_stride'])

    if btype == 'int':
        b = random.randint(1, 8)
    elif btype == 'rank1':
        b = Layout(random.randint(2, 8), random.choice([1, 2, -1, -2, 3, 4]))
    elif btype == 'tuple':
        b = tuple(random.choice([None, random.randint(1, 4), Layout(random.randint(2, 5), random.randint(1, 3))]) for _ in range(rank))
    elif btype == 'hierarchical':
        bshape = tuple(random.randint(1, 4) for _ in range(random.randint(2, 3)))
        bstride = tuple(random.randint(1, 4) for _ in bshape)
        b = Layout(bshape, bstride)
    elif btype == 'none':
        b = None
    elif btype == 'zero_stride':
        b = Layout(random.randint(2, 8), 0)

    if not is_valid_composition_case(a, b):
        continue

    total_count += 1

    try:
        r_local = composition(a, b)
        r_ref = compRef(a, b)
        if r_local != r_ref:
            print(f"FAIL: composition({a}, {b})")
            print(f"  local: {r_local}")
            print(f"  ref:   {r_ref}")
            fail_count += 1
    except Exception as e:
        print(f"EXCEPTION: composition({a}, {b}): {e}")
        fail_count += 1

