import random
random.seed(2024)

from pycute.layout import Layout as LayoutRef, composition as compRef, flatten
from pycute import Layout, composition, coalesce

def is_valid_composition_case(A, B):
    if B is None:
        return True
    if isinstance(B, int):
        return True
    if isinstance(B, tuple):
        return len(A) >= len(B)
    if isinstance(B.shape, tuple):
        return True
    flat_A = coalesce(A)
    rest_stride = B.stride
    if rest_stride == 0:
        return True
    for curr_shape in flatten(flat_A.shape)[:-1]:
        if curr_shape == 0:
            return False
        if not (curr_shape % rest_stride == 0 or rest_stride % curr_shape == 0):
            return False
    return True

# Generate valid random tests
mismatches = 0
local_only_fail = 0
ref_only_fail = 0
both_fail = 0
total = 0

for trial in range(2000):
    rank = random.randint(1, 3)

    # Generate A as a flat layout
    a_shape = tuple(random.randint(1, 6) for _ in range(rank))
    a_stride = tuple(random.choice([1, 2, 3, 4, 5, -1, -2]) for _ in range(rank))
    a = Layout(a_shape, a_stride)

    # Generate B
    btype = random.choice(['int', 'rank1', 'tuple', 'hierarchical', 'none', 'zero_stride'])
    flat_A = coalesce(a)
    a_flat_shapes = list(flatten(flat_A.shape)[:-1])

    if btype == 'int':
        b = random.randint(1, 10)
    elif btype == 'rank1':
        valid_strides = [st for st in [1, 2, 3, 4, 5, 6, -1, -2, -3]
                        if all(s % st == 0 or st % s == 0 for s in a_flat_shapes if s != 0)]
        if not valid_strides:
            continue
        b = Layout(random.randint(2, 12), random.choice(valid_strides))
    elif btype == 'tuple':
        b = tuple(random.choice([None, random.randint(1, 6), 
                                  Layout(random.randint(2, 5), random.randint(1, 3))])
                 for _ in range(rank))
    elif btype == 'hierarchical':
        hrank = random.randint(2, 3)
        bshape = []
        bstride = []
        for _ in range(hrank):
            s = random.randint(1, 5)
            valid = [st for st in [1, 2, 3, 4, 5] 
                    if all(a_s % st == 0 or st % a_s == 0 for a_s in a_flat_shapes if a_s != 0)]
            if not valid:
                break
            bshape.append(s)
            bstride.append(random.choice(valid))
        else:
            b = Layout(tuple(bshape), tuple(bstride))
            continue  # don't run if break
        continue  # break happened
    elif btype == 'none':
        b = None
    elif btype == 'zero_stride':
        b = Layout(random.randint(2, 10), 0)

    if not is_valid_composition_case(a, b):
        continue

    total += 1

    try:
        r_local = composition(a, b)
    except Exception:
        try:
            compRef(a, b)
            local_only_fail += 1
            mismatches += 1
        except Exception:
            both_fail += 1
        continue

    try:
        r_ref = compRef(a, b)
    except Exception:
        ref_only_fail += 1
        mismatches += 1
        continue

    if r_local != r_ref:
        mismatches += 1
        print(f"MISMATCH: composition({a}, {b})")
        print(f"  local: {r_local}")
        print(f"  ref:   {r_ref}")

print(f"Mismatches: {mismatches}, Local only fail: {local_only_fail}, Ref only fail: {ref_only_fail}, Both fail: {both_fail}, Total: {total}")
